const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─── ENUMS ───────────────────────────────────────────────────────────────────\n\nenum UserRole {\n  SUPER_ADMIN\n  ADMIN\n  MANAGER\n  AGENT\n}\n\nenum ConversationStatus {\n  OPEN\n  AI_HANDLING\n  WAITING_HUMAN\n  HUMAN_HANDLING\n  RESOLVED\n  CLOSED\n  SPAM\n}\n\nenum MessageDirection {\n  INBOUND\n  OUTBOUND\n}\n\nenum MessageStatus {\n  PENDING\n  SENT\n  DELIVERED\n  READ\n  FAILED\n}\n\nenum MessageType {\n  TEXT\n  IMAGE\n  VIDEO\n  AUDIO\n  DOCUMENT\n  STICKER\n  LOCATION\n  CONTACT\n  TEMPLATE\n  INTERACTIVE\n}\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  QUALIFIED\n  PROPOSAL_SENT\n  NEGOTIATING\n  WON\n  LOST\n  DISQUALIFIED\n}\n\nenum LeadSource {\n  WHATSAPP\n  WEBSITE\n  REFERRAL\n  INBOUND_EMAIL\n  OUTBOUND\n  CAMPAIGN\n  FORM\n  IMPORT\n  AI_CHAT\n  MANUAL\n  META_ADS\n  WEBHOOK\n  OTHER\n}\n\nenum LeadIntegrationProvider {\n  META_ADS\n  CUSTOM_WEBHOOK\n}\n\nenum LeadIntegrationStatus {\n  ACTIVE\n  PAUSED\n  ERROR\n}\n\nenum LeadPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum LeadActivityType {\n  CREATED\n  STATUS_CHANGED\n  ASSIGNED\n  UNASSIGNED\n  SCORED\n  NOTE_ADDED\n  TAG_ADDED\n  TAG_REMOVED\n  CONTACTED\n  RESPONDED\n  MEETING_BOOKED\n  PROPOSAL_SENT\n  CONVERTED\n  WON\n  LOST\n  DISQUALIFIED\n  FIELD_UPDATED\n  CUSTOM\n}\n\nenum TemplateType {\n  TEXT\n  IMAGE\n  DOCUMENT\n  VIDEO\n  LOCATION\n  CONTACTS\n}\n\nenum TemplateStatus {\n  DRAFT\n  ACTIVE\n  ARCHIVED\n}\n\nenum TemplateCategory {\n  GREETING\n  FOLLOW_UP\n  PROMOTION\n  PAYMENT_REMINDER\n  ORDER_UPDATE\n  SUPPORT\n  FEEDBACK\n  REVIEW\n  APPOINTMENT\n  GENERAL\n}\n\nenum TemplateActivityType {\n  CREATED\n  UPDATED\n  ACTIVATED\n  ARCHIVED\n  DELETED\n  USED\n  SENT\n  DELIVERED\n  FAILED\n  CONVERTED\n  VARIABLE_RENDERED\n  PREVIEWED\n}\n\nenum DealStage {\n  LEAD_IN\n  QUALIFIED\n  PROPOSAL\n  NEGOTIATION\n  WON\n  LOST\n}\n\nenum DealSource {\n  LEAD_CONVERSION\n  WHATSAPP\n  MANUAL\n  AI_CHAT\n  REFERRAL\n  CAMPAIGN\n  WEBSITE\n  IMPORT\n  OTHER\n}\n\nenum DealPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum DealLossReason {\n  PRICE\n  COMPETITOR\n  TIMING\n  NO_BUDGET\n  NO_DECISION\n  WRONG_FIT\n  GHOSTED\n  OTHER\n}\n\nenum DealActivityType {\n  CREATED\n  STAGE_CHANGED\n  ASSIGNED\n  UNASSIGNED\n  VALUE_UPDATED\n  PROBABILITY_UPDATED\n  NOTE_ADDED\n  TAG_ADDED\n  TAG_REMOVED\n  CONTACTED\n  RESPONDED\n  PROPOSAL_SENT\n  MEETING_BOOKED\n  LINE_ITEM_ADDED\n  LINE_ITEM_REMOVED\n  PAYMENT_RECEIVED\n  WON\n  LOST\n  REOPENED\n  FIELD_UPDATED\n  CUSTOM\n}\n\nenum TaskStatus {\n  TODO\n  IN_PROGRESS\n  DONE\n  CANCELLED\n}\n\nenum TaskPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum TaskSource {\n  MANUAL\n  AI_CHAT\n  WHATSAPP\n  RECURRING\n  AUTO_FOLLOW_UP\n  IMPORT\n  OTHER\n}\n\nenum TaskActivityType {\n  CREATED\n  STATUS_CHANGED\n  ASSIGNED\n  UNASSIGNED\n  PRIORITY_CHANGED\n  DUE_DATE_CHANGED\n  TITLE_CHANGED\n  DESCRIPTION_CHANGED\n  COMMENT_ADDED\n  SUBTASK_ADDED\n  SUBTASK_COMPLETED\n  SUBTASK_REMOVED\n  WATCHER_ADDED\n  WATCHER_REMOVED\n  TIME_LOGGED\n  RESCHEDULED\n  REMINDER_SENT\n  RECURRENCE_TRIGGERED\n  COMPLETED\n  CANCELLED\n  REOPENED\n  FIELD_UPDATED\n  CUSTOM\n}\n\nenum TaskRecurrenceFrequency {\n  DAILY\n  WEEKLY\n  MONTHLY\n  QUARTERLY\n  YEARLY\n  CUSTOM_DAYS\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n  EXPIRED\n}\n\nenum AiProvider {\n  GEMINI\n  OPENAI\n  ANTHROPIC\n  GROQ\n  DEEPSEEK\n  XAI\n  MISTRAL\n  TOGETHER\n  MOONSHOT\n  GLM\n  QWEN\n  STEPFUN\n  OLLAMA\n  OPENROUTER\n  CUSTOM\n}\n\nenum PaymentProvider {\n  RAZORPAY\n  STRIPE\n  CASHFREE\n  PHONEPE\n  PAYU\n  NONE\n}\n\nenum WaAccountStatus {\n  DISCONNECTED\n  QR_PENDING\n  CONNECTING\n  CONNECTED\n  BANNED\n  ERROR\n}\n\nenum AuditAction {\n  CREATE\n  UPDATE\n  DELETE\n  AI_TOOL_CALL\n  AI_REPLY\n  PAYMENT_CREATED\n  PAYMENT_RECEIVED\n  WA_SESSION_START\n  WA_SESSION_END\n  USER_LOGIN\n  USER_LOGOUT\n  SETTINGS_CHANGE\n}\n\n// ─── COMPANY ──────────────────────────────────────────────────────────────────\n\nmodel Company {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique\n  email     String?\n  phone     String?\n  website   String?\n  logoUrl   String?\n  publicUrl String? // Public URL for webhooks/integrations (e.g., https://yourdomain.com)\n  timezone  String   @default(\"UTC\")\n  isActive  Boolean  @default(true)\n  setupDone Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users               User[]\n  whatsappAccounts    WhatsAppAccount[]\n  contacts            Contact[]\n  conversations       Conversation[]\n  leads               Lead[]\n  deals               Deal[]\n  tasks               Task[]\n  payments            Payment[]\n  broadcasts          Broadcast[]\n  templates           Template[]\n  sequences           Sequence[]\n  sequenceEnrollments SequenceEnrollment[]\n  auditLogs           AuditLog[]\n  aiConfig            AiConfig?\n  paymentConfig       PaymentConfig?\n  webhookEndpoints    WebhookEndpoint[]\n\n  @@index([slug])\n  @@index([isActive])\n}\n\n// ─── USER ─────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id               String    @id @default(cuid())\n  companyId        String\n  email            String\n  passwordHash     String\n  firstName        String\n  lastName         String\n  avatarUrl        String?\n  role             UserRole  @default(AGENT)\n  isActive         Boolean   @default(true)\n  refreshTokenHash String?\n  lastLoginAt      DateTime?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n\n  company           Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  assignedConvs     Conversation[] @relation(\"AssignedAgent\")\n  assignedLeads     Lead[]         @relation(\"AssignedAgent\")\n  assignedDeals     Deal[]         @relation(\"AssignedAgent\")\n  assignedTasks     Task[]         @relation(\"AssignedAgent\")\n  createdTasks      Task[]         @relation(\"CreatedBy\")\n  createdBroadcasts Broadcast[]    @relation(\"BroadcastCreatedBy\")\n  createdSequences  Sequence[]     @relation(\"SequenceCreator\")\n  createdTemplates  Template[]     @relation(\"TemplateCreator\")\n  auditLogs         AuditLog[]\n\n  @@unique([companyId, email])\n  @@index([companyId])\n  @@index([email])\n}\n\n// ─── WHATSAPP ACCOUNT ─────────────────────────────────────────────────────────\n\nmodel WhatsAppAccount {\n  id                String          @id @default(cuid())\n  companyId         String\n  phoneNumber       String\n  displayName       String?\n  status            WaAccountStatus @default(DISCONNECTED)\n  provider          String          @default(\"baileys\")\n  accessTokenEnc    String?\n  phoneNumberId     String?\n  sessionDataEnc    Bytes?\n  qrCode            String?\n  warmupStage       Int             @default(0)\n  warmupStartedAt   DateTime?\n  dailyMessageLimit Int             @default(50)\n  messagesSentToday Int             @default(0)\n  lastResetAt       DateTime?\n  consecutiveErrors Int             @default(0)\n  lastErrorAt       DateTime?\n  lastConnectedAt   DateTime?\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n\n  company       Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  conversations Conversation[]\n  messages      Message[]\n\n  @@unique([companyId, phoneNumber])\n  @@index([companyId])\n  @@index([status])\n}\n\n// ─── CONTACT ──────────────────────────────────────────────────────────────────\n\nmodel Contact {\n  id             String    @id @default(cuid())\n  companyId      String\n  phoneNumber    String\n  displayName    String?\n  firstName      String?\n  lastName       String?\n  email          String?\n  avatarUrl      String?\n  tags           String[]\n  customFields   Json      @default(\"{}\")\n  notes          String?\n  lifecycleStage String    @default(\"SUBSCRIBER\")\n  score          Int       @default(0)\n  companyName    String?\n  jobTitle       String?\n  address        String?\n  socialLinks    Json      @default(\"{}\")\n  referredById   String?\n  isBlocked      Boolean   @default(false)\n  optedOut       Boolean   @default(false)\n  optedOutAt     DateTime?\n  lastSeenAt     DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n  deletedAt      DateTime?\n\n  company             Company              @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  referredBy          Contact?             @relation(\"ContactReferrals\", fields: [referredById], references: [id])\n  referrals           Contact[]            @relation(\"ContactReferrals\")\n  conversations       Conversation[]\n  leads               Lead[]\n  deals               Deal[]\n  tasks               Task[]\n  payments            Payment[]\n  contactNotes        ContactNote[]\n  broadcastRecipients BroadcastRecipient[]\n  enrollments         SequenceEnrollment[]\n\n  @@unique([companyId, phoneNumber])\n  @@index([companyId])\n  @@index([phoneNumber])\n  @@index([companyId, deletedAt])\n  @@index([tags])\n  @@index([companyId, lifecycleStage])\n  @@index([companyId, score])\n}\n\n// ─── CONVERSATION ─────────────────────────────────────────────────────────────\n\nmodel Conversation {\n  id                String             @id @default(cuid())\n  companyId         String\n  contactId         String\n  whatsappAccountId String\n  assignedAgentId   String?\n  status            ConversationStatus @default(OPEN)\n  aiEnabled         Boolean            @default(true)\n  unreadCount       Int                @default(0)\n  lastMessageAt     DateTime?\n  lastMessageText   String?\n  resolvedAt        DateTime?\n  metadata          Json               @default(\"{}\")\n  createdAt         DateTime           @default(now())\n  updatedAt         DateTime           @updatedAt\n\n  company         Company         @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact         Contact         @relation(fields: [contactId], references: [id])\n  whatsappAccount WhatsAppAccount @relation(fields: [whatsappAccountId], references: [id])\n  assignedAgent   User?           @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  messages        Message[]\n  aiContextCache  AiContextCache?\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([status])\n  @@index([companyId, status])\n  @@index([lastMessageAt])\n}\n\n// ─── MESSAGE ──────────────────────────────────────────────────────────────────\n\nmodel Message {\n  id                String           @id @default(cuid())\n  companyId         String\n  conversationId    String\n  whatsappAccountId String\n  whatsappMessageId String?\n  idempotencyKey    String?          @unique\n  direction         MessageDirection\n  type              MessageType      @default(TEXT)\n  status            MessageStatus    @default(PENDING)\n  body              String?\n  mediaUrl          String?\n  mediaType         String?\n  mediaSizeBytes    Int?\n  mediaCaption      String?\n  latitude          Float?\n  longitude         Float?\n  replyToMessageId  String?\n  isAiGenerated     Boolean          @default(false)\n  aiProvider        String?\n  aiModel           String?\n  aiTokensUsed      Int?\n  aiLatencyMs       Int?\n  errorMessage      String?\n  sentAt            DateTime?\n  deliveredAt       DateTime?\n  readAt            DateTime?\n  failedAt          DateTime?\n  createdAt         DateTime         @default(now())\n\n  conversation    Conversation    @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  whatsappAccount WhatsAppAccount @relation(fields: [whatsappAccountId], references: [id])\n  replyTo         Message?        @relation(\"ReplyThread\", fields: [replyToMessageId], references: [id])\n  replies         Message[]       @relation(\"ReplyThread\")\n\n  @@index([conversationId])\n  @@index([whatsappMessageId])\n  @@index([idempotencyKey])\n  @@index([companyId, createdAt])\n  @@index([direction, status])\n}\n\n// ─── LEAD ─────────────────────────────────────────────────────────────────────\n\nmodel Lead {\n  id                 String       @id @default(cuid())\n  companyId          String\n  contactId          String\n  assignedAgentId    String?\n  title              String\n  status             LeadStatus   @default(NEW)\n  source             LeadSource   @default(MANUAL)\n  priority           LeadPriority @default(MEDIUM)\n  score              Int          @default(0)\n  probability        Int          @default(20) // 0-100\n  estimatedValue     Float?\n  currency           String       @default(\"INR\")\n  tags               String[]     @default([])\n  notes              String?\n  customFields       Json         @default(\"{}\")\n  expectedCloseAt    DateTime?\n  nextActionAt       DateTime?\n  nextActionNote     String?\n  qualifiedAt        DateTime?\n  disqualifiedAt     DateTime?\n  disqualifiedReason String?\n  lostReason         String?\n  wonAt              DateTime?\n  lostAt             DateTime?\n  slaFirstResponseAt DateTime?\n  createdAt          DateTime     @default(now())\n  updatedAt          DateTime     @updatedAt\n  deletedAt          DateTime?\n\n  company       Company          @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact          @relation(fields: [contactId], references: [id])\n  assignedAgent User?            @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  deals         Deal[]\n  tasks         Task[]\n  activities    LeadActivity[]\n  scoreEvents   LeadScoreEvent[]\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([status])\n  @@index([companyId, status])\n  @@index([companyId, source])\n  @@index([companyId, priority])\n  @@index([companyId, assignedAgentId])\n  @@index([companyId, nextActionAt])\n}\n\nmodel LeadActivity {\n  id        String           @id @default(cuid())\n  leadId    String\n  companyId String\n  type      LeadActivityType\n  actorType String // user | ai | system | whatsapp\n  actorId   String? // userId if actor is a user\n  title     String\n  body      String?\n  metadata  Json             @default(\"{}\")\n  createdAt DateTime         @default(now())\n\n  lead Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  @@index([leadId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel LeadScoreEvent {\n  id        String   @id @default(cuid())\n  leadId    String\n  companyId String\n  delta     Int\n  newScore  Int\n  reason    String\n  source    String // auto | manual | ai | rule:<name>\n  createdAt DateTime @default(now())\n\n  lead Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  @@index([leadId, createdAt])\n}\n\n// ─── LEAD INTAKE INTEGRATIONS (Meta Ads + custom webhooks) ──────────────────\n\nmodel LeadIntakeIntegration {\n  id        String                  @id @default(cuid())\n  companyId String\n  provider  LeadIntegrationProvider\n  name      String\n  status    LeadIntegrationStatus   @default(ACTIVE)\n\n  // Meta-specific fields. AppSecret + PageAccessToken are encrypted at rest\n  // using the existing `encrypt`/`decrypt` helpers from @wacrm/shared.\n  metaPageId             String?\n  metaPageName           String?\n  metaAppSecretEnc       String?\n  metaVerifyToken        String?\n  metaPageAccessTokenEnc String?\n\n  // Stats\n  lastEventAt DateTime?\n  lastError   String?\n  totalLeads  Int       @default(0)\n\n  // Defaults applied to every lead created via this integration\n  defaultTags     String[]     @default([])\n  defaultPriority LeadPriority @default(MEDIUM)\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  @@index([companyId])\n  @@index([companyId, provider])\n}\n\n// ─── DEAL ─────────────────────────────────────────────────────────────────────\n\nmodel Deal {\n  id              String          @id @default(cuid())\n  companyId       String\n  contactId       String\n  leadId          String?\n  assignedAgentId String?\n  title           String\n  stage           DealStage       @default(LEAD_IN)\n  source          DealSource      @default(MANUAL)\n  priority        DealPriority    @default(MEDIUM)\n  value           Float\n  currency        String          @default(\"INR\")\n  probability     Int             @default(20)\n  weightedValue   Float? // value * probability/100, maintained by service\n  tags            String[]        @default([])\n  expectedCloseAt DateTime?\n  nextActionAt    DateTime?\n  nextActionNote  String?\n  qualifiedAt     DateTime?\n  proposalSentAt  DateTime?\n  wonAt           DateTime?\n  lostAt          DateTime?\n  lostReason      String? // legacy free-text reason\n  lostReasonCode  DealLossReason? // taxonomic reason for analytics\n  salesCycleDays  Int? // days from createdAt → wonAt/lostAt\n  lastTouchedAt   DateTime? // updated by WhatsApp ingest hook\n  notes           String?\n  customFields    Json            @default(\"{}\")\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n  deletedAt       DateTime?\n\n  company       Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact        @relation(fields: [contactId], references: [id])\n  lead          Lead?          @relation(fields: [leadId], references: [id])\n  assignedAgent User?          @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  payments      Payment[]\n  tasks         Task[]\n  activities    DealActivity[]\n  lineItems     DealLineItem[]\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([stage])\n  @@index([companyId, stage])\n  @@index([companyId, source])\n  @@index([companyId, priority])\n  @@index([companyId, assignedAgentId])\n  @@index([companyId, nextActionAt])\n  @@index([companyId, lastTouchedAt])\n}\n\nmodel DealActivity {\n  id        String           @id @default(cuid())\n  dealId    String\n  companyId String\n  type      DealActivityType\n  actorType String // user | ai | system | whatsapp | payment\n  actorId   String?\n  title     String\n  body      String?\n  metadata  Json             @default(\"{}\")\n  createdAt DateTime         @default(now())\n\n  deal Deal @relation(fields: [dealId], references: [id], onDelete: Cascade)\n\n  @@index([dealId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel DealLineItem {\n  id          String   @id @default(cuid())\n  dealId      String\n  companyId   String\n  productId   String?\n  name        String\n  description String?\n  quantity    Float    @default(1)\n  unitPrice   Float\n  discount    Float    @default(0) // percent\n  taxRate     Float    @default(0) // percent\n  total       Float\n  position    Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  deal    Deal     @relation(fields: [dealId], references: [id], onDelete: Cascade)\n  product Product? @relation(fields: [productId], references: [id])\n\n  @@index([dealId])\n  @@index([companyId])\n}\n\n// ─── TASK ─────────────────────────────────────────────────────────────────────\n\nmodel Task {\n  id              String       @id @default(cuid())\n  companyId       String\n  contactId       String?\n  dealId          String?\n  leadId          String?\n  parentTaskId    String? // for subtasks (self-relation below)\n  recurrenceId    String? // FK to TaskRecurrence if part of a recurring series\n  assignedAgentId String?\n  createdById     String?\n  title           String\n  description     String?\n  status          TaskStatus   @default(TODO)\n  priority        TaskPriority @default(MEDIUM)\n  source          TaskSource   @default(MANUAL)\n  tags            String[]     @default([])\n  position        Int          @default(0)\n  estimatedHours  Float?\n  actualHours     Float?       @default(0)\n  dueAt           DateTime?\n  startedAt       DateTime?\n  completedAt     DateTime?\n  cancelledAt     DateTime?\n  cancelReason    String?\n  cleanupAfter    DateTime? // OpenClaw-style TTL — set when task reaches DONE/CANCELLED\n  reminderOffsets Int[]        @default([30]) // minutes before dueAt to fire each reminder\n  remindersSent   DateTime[]   @default([]) // history of reminder fire times\n  reminderSentAt  DateTime? // legacy column kept for backwards compat with reminder.processor.ts\n  createdAt       DateTime     @default(now())\n  updatedAt       DateTime     @updatedAt\n\n  company       Company         @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact?        @relation(fields: [contactId], references: [id])\n  deal          Deal?           @relation(fields: [dealId], references: [id])\n  lead          Lead?           @relation(fields: [leadId], references: [id])\n  recurrence    TaskRecurrence? @relation(fields: [recurrenceId], references: [id])\n  assignedAgent User?           @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  createdBy     User?           @relation(\"CreatedBy\", fields: [createdById], references: [id])\n  parent        Task?           @relation(\"TaskSubtasks\", fields: [parentTaskId], references: [id], onDelete: Cascade)\n  subtasks      Task[]          @relation(\"TaskSubtasks\")\n  activities    TaskActivity[]\n  comments      TaskComment[]\n  watchers      TaskWatcher[]\n\n  @@index([companyId])\n  @@index([assignedAgentId])\n  @@index([dueAt])\n  @@index([status])\n  @@index([companyId, source])\n  @@index([companyId, parentTaskId])\n  @@index([companyId, recurrenceId])\n  @@index([companyId, cleanupAfter])\n  @@index([leadId])\n}\n\nmodel TaskActivity {\n  id        String           @id @default(cuid())\n  taskId    String\n  companyId String\n  type      TaskActivityType\n  actorType String // user | ai | system | whatsapp | recurrence\n  actorId   String?\n  title     String\n  body      String?\n  metadata  Json             @default(\"{}\")\n  createdAt DateTime         @default(now())\n\n  task Task @relation(fields: [taskId], references: [id], onDelete: Cascade)\n\n  @@index([taskId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel TaskComment {\n  id        String   @id @default(cuid())\n  taskId    String\n  companyId String\n  authorId  String? // null = AI / system\n  body      String\n  mentions  String[] @default([])\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  task Task @relation(fields: [taskId], references: [id], onDelete: Cascade)\n\n  @@index([taskId, createdAt])\n}\n\nmodel TaskWatcher {\n  id        String   @id @default(cuid())\n  taskId    String\n  userId    String\n  companyId String\n  createdAt DateTime @default(now())\n\n  task Task @relation(fields: [taskId], references: [id], onDelete: Cascade)\n\n  @@unique([taskId, userId])\n  @@index([userId])\n}\n\nmodel TaskRecurrence {\n  id                      String                  @id @default(cuid())\n  companyId               String\n  templateTitle           String\n  templateBody            String?\n  templatePriority        TaskPriority            @default(MEDIUM)\n  templateAssignedAgentId String?\n  frequency               TaskRecurrenceFrequency\n  intervalDays            Int? // for CUSTOM_DAYS\n  daysOfWeek              Int[]                   @default([]) // for WEEKLY: 0=Sun..6=Sat\n  dayOfMonth              Int? // for MONTHLY\n  startsAt                DateTime\n  endsAt                  DateTime?\n  nextRunAt               DateTime\n  lastRunAt               DateTime?\n  totalGenerated          Int                     @default(0)\n  isActive                Boolean                 @default(true)\n  createdAt               DateTime                @default(now())\n  updatedAt               DateTime                @updatedAt\n\n  tasks Task[]\n\n  @@index([companyId])\n  @@index([nextRunAt, isActive])\n}\n\n// ─── AI CONFIG ────────────────────────────────────────────────────────────────\n\nmodel AiConfig {\n  id                 String     @id @default(cuid())\n  companyId          String     @unique\n  provider           AiProvider @default(GEMINI)\n  model              String     @default(\"gemini-2.0-flash\")\n  apiKeyEncrypted    String?\n  baseUrl            String?\n  systemPrompt       String     @default(\"You are a helpful sales assistant. Help the customer and capture their information.\")\n  tone               String     @default(\"professional\")\n  maxTokens          Int        @default(1024)\n  temperature        Float      @default(0.7)\n  autoReplyEnabled   Boolean    @default(true)\n  toolCallingEnabled Boolean    @default(true)\n  testStatus         String?\n  testError          String?\n  updatedAt          DateTime   @updatedAt\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n}\n\nmodel AiContextCache {\n  id             String   @id @default(cuid())\n  conversationId String   @unique\n  messages       Json\n  tokenCount     Int\n  pruneCount     Int      @default(0)\n  updatedAt      DateTime @updatedAt\n\n  conversation Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n\n  @@index([conversationId])\n}\n\n// ─── PAYMENT ──────────────────────────────────────────────────────────────────\n\nmodel PaymentConfig {\n  id              String          @id @default(cuid())\n  companyId       String          @unique\n  provider        PaymentProvider @default(NONE)\n  keyEncrypted    String?\n  secretEncrypted String?\n  webhookSecret   String?\n  currency        String          @default(\"INR\")\n  testMode        Boolean         @default(true)\n  updatedAt       DateTime        @updatedAt\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n}\n\nmodel Payment {\n  id             String          @id @default(cuid())\n  companyId      String\n  contactId      String?\n  dealId         String?\n  provider       PaymentProvider\n  externalId     String?\n  linkUrl        String?\n  amount         Int\n  currency       String          @default(\"INR\")\n  description    String?\n  status         PaymentStatus   @default(PENDING)\n  paidAt         DateTime?\n  refundedAt     DateTime?\n  webhookPayload Json?\n  idempotencyKey String          @unique\n  createdAt      DateTime        @default(now())\n  updatedAt      DateTime        @updatedAt\n\n  company Company  @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact Contact? @relation(fields: [contactId], references: [id])\n  deal    Deal?    @relation(fields: [dealId], references: [id])\n\n  @@index([companyId])\n  @@index([externalId])\n  @@index([status])\n  @@index([idempotencyKey])\n}\n\n// ─── BROADCAST ────────────────────────────────────────────────────────────────\n\nenum BroadcastStatus {\n  DRAFT\n  SCHEDULED\n  SENDING\n  COMPLETED\n  CANCELLED\n  PAUSED\n  FAILED\n}\n\nenum BroadcastRecipientStatus {\n  QUEUED\n  SENDING\n  SENT\n  DELIVERED\n  READ\n  FAILED\n  SKIPPED\n}\n\nenum BroadcastActivityType {\n  CREATED\n  UPDATED\n  AUDIENCE_CHANGED\n  SCHEDULED\n  STARTED\n  PAUSED\n  RESUMED\n  CANCELLED\n  COMPLETED\n  FAILED\n  RECIPIENT_SENT\n  RECIPIENT_FAILED\n  RECIPIENT_DELIVERED\n  RECIPIENT_READ\n  RETRY_FAILED\n  CUSTOM\n}\n\nmodel Broadcast {\n  id               String          @id @default(cuid())\n  companyId        String\n  name             String\n  message          String\n  mediaUrl         String?\n  mediaType        String?\n  mediaCaption     String?\n  templateName     String?\n  variables        Json            @default(\"{}\")\n  audienceFilter   Json?\n  // Legacy raw audience inputs (kept for backwards compat with the old worker)\n  targetTags       String[]        @default([])\n  targetContactIds String[]        @default([])\n  status           BroadcastStatus @default(DRAFT)\n  throttleMs       Int             @default(2000)\n  scheduledAt      DateTime?\n  startedAt        DateTime?\n  completedAt      DateTime?\n  totalCount       Int             @default(0) // legacy alias for totalRecipients\n  totalRecipients  Int             @default(0)\n  sentCount        Int             @default(0)\n  failedCount      Int             @default(0)\n  deliveredCount   Int             @default(0)\n  readCount        Int             @default(0)\n  skippedCount     Int             @default(0)\n  errorMessage     String?\n  createdById      String?\n  createdAt        DateTime        @default(now())\n  updatedAt        DateTime        @updatedAt\n\n  company    Company              @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  createdBy  User?                @relation(\"BroadcastCreatedBy\", fields: [createdById], references: [id])\n  recipients BroadcastRecipient[]\n  activities BroadcastActivity[]\n\n  @@index([companyId])\n  @@index([scheduledAt])\n  @@index([companyId, status])\n  @@index([scheduledAt, status])\n  @@index([companyId, createdAt])\n}\n\nmodel BroadcastRecipient {\n  id                String                   @id @default(cuid())\n  broadcastId       String\n  companyId         String\n  contactId         String\n  toPhone           String\n  status            BroadcastRecipientStatus @default(QUEUED)\n  /// Rendered, personalized message body for THIS recipient. Stored so retries\n  /// don't re-render and the audit shows the exact text sent.\n  renderedText      String\n  mediaUrl          String?\n  whatsappMessageId String?\n  errorMessage      String?\n  queuedAt          DateTime                 @default(now())\n  sentAt            DateTime?\n  deliveredAt       DateTime?\n  readAt            DateTime?\n  failedAt          DateTime?\n\n  broadcast Broadcast @relation(fields: [broadcastId], references: [id], onDelete: Cascade)\n  contact   Contact   @relation(fields: [contactId], references: [id])\n\n  @@unique([broadcastId, contactId])\n  @@index([broadcastId, status])\n  @@index([companyId, contactId])\n}\n\nmodel BroadcastActivity {\n  id          String                @id @default(cuid())\n  broadcastId String\n  companyId   String\n  type        BroadcastActivityType\n  actorType   String\n  actorId     String?\n  title       String\n  body        String?\n  metadata    Json                  @default(\"{}\")\n  createdAt   DateTime              @default(now())\n\n  broadcast Broadcast @relation(fields: [broadcastId], references: [id], onDelete: Cascade)\n\n  @@index([broadcastId, createdAt])\n  @@index([companyId, type])\n}\n\n// ─── AUDIT LOG ────────────────────────────────────────────────────────────────\n\nmodel AuditLog {\n  id         String      @id @default(cuid())\n  companyId  String\n  userId     String?\n  action     AuditAction\n  entityType String?\n  entityId   String?\n  oldValue   Json?\n  newValue   Json?\n  ipAddress  String?\n  createdAt  DateTime    @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  user    User?   @relation(fields: [userId], references: [id])\n\n  @@index([companyId])\n  @@index([action])\n  @@index([entityType, entityId])\n  @@index([createdAt])\n}\n\n// ─── WEBHOOK ENDPOINT ─────────────────────────────────────────────────────────\n\nmodel WebhookEndpoint {\n  id        String   @id @default(cuid())\n  companyId String\n  url       String\n  secret    String\n  events    String[]\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n\n  @@index([companyId])\n}\n\n// ─── CONTACT NOTE ────────────────────────────────────────────────────────────\n\nmodel ContactNote {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String\n  authorId  String?\n  content   String\n  createdAt DateTime @default(now())\n\n  contact Contact @relation(fields: [contactId], references: [id], onDelete: Cascade)\n\n  @@index([contactId])\n  @@index([companyId])\n}\n\n// ─── TAG ─────────────────────────────────────────────────────────────────────\n\nmodel Tag {\n  id          String  @id @default(cuid())\n  companyId   String\n  name        String\n  color       String  @default(\"#8b5cf6\")\n  description String?\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ─── SEGMENT ─────────────────────────────────────────────────────────────────\n\nmodel Segment {\n  id         String   @id @default(cuid())\n  companyId  String\n  name       String\n  type       String   @default(\"DYNAMIC\") // DYNAMIC or STATIC\n  filters    Json     @default(\"{}\") // For DYNAMIC: filter rules\n  contactIds String[] // For STATIC: manually added contacts\n  count      Int      @default(0)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ─── CUSTOM FIELD DEFINITION ─────────────────────────────────────────────────\n\nmodel CustomFieldDefinition {\n  id         String   @id @default(cuid())\n  companyId  String\n  entityType String // \"contact\", \"lead\", \"deal\"\n  fieldName  String\n  fieldType  String // \"text\", \"number\", \"date\", \"select\", \"multiselect\"\n  options    String[] // For select/multiselect\n  required   Boolean  @default(false)\n  sortOrder  Int      @default(0)\n  createdAt  DateTime @default(now())\n\n  @@unique([companyId, entityType, fieldName])\n  @@index([companyId, entityType])\n}\n\n// ─── NOTIFICATION ────────────────────────────────────────────────────────────\n\nmodel Notification {\n  id        String   @id @default(cuid())\n  companyId String\n  userId    String?\n  title     String\n  body      String\n  type      String   @default(\"info\") // info, success, warning, error\n  link      String?\n  read      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  @@index([companyId, userId, read])\n  @@index([companyId, createdAt])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 2: COMMUNICATION\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Template {\n  id        String           @id @default(cuid())\n  companyId String\n  name      String\n  type      TemplateType     @default(TEXT)\n  status    TemplateStatus   @default(DRAFT)\n  category  TemplateCategory @default(GENERAL)\n  body      String           @db.Text\n  variables Json             @default(\"{}\")\n  mediaUrl  String?\n  language  String           @default(\"en\")\n  tags      String[]         @default([])\n\n  // Usage tracking\n  useCount       Int       @default(0)\n  lastUsedAt     DateTime?\n  sentCount      Int       @default(0)\n  deliveredCount Int       @default(0)\n  failedCount    Int       @default(0)\n\n  // Conversions\n  conversionCount Int @default(0)\n\n  // A/B testing\n  variantOf   String?\n  variantName String?\n\n  createdById String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relations\n  company     Company            @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  activities  TemplateActivity[]\n  createdBy   User?              @relation(\"TemplateCreator\", fields: [createdById], references: [id])\n  variants    Template[]         @relation(\"TemplateVariants\")\n  parent      Template?          @relation(\"TemplateVariants\", fields: [variantOf], references: [id])\n  usedInSteps SequenceStep[]\n\n  @@unique([companyId, name])\n  @@index([companyId, status])\n  @@index([companyId, category])\n  @@index([companyId, useCount])\n  @@index([variantOf])\n}\n\nmodel TemplateActivity {\n  id         String               @id @default(cuid())\n  templateId String\n  companyId  String\n  type       TemplateActivityType\n  actorType  String\n  actorId    String?\n  title      String\n  body       String?\n  metadata   Json                 @default(\"{}\")\n  createdAt  DateTime             @default(now())\n\n  template Template @relation(fields: [templateId], references: [id], onDelete: Cascade)\n\n  @@index([templateId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel CannedResponse {\n  id        String @id @default(cuid())\n  companyId String\n  shortcut  String // e.g. \"/hello\"\n  body      String\n\n  @@unique([companyId, shortcut])\n  @@index([companyId])\n}\n\nenum SequenceStatus {\n  DRAFT\n  ACTIVE\n  PAUSED\n  ARCHIVED\n}\n\nenum EnrollmentStatus {\n  ACTIVE\n  PAUSED\n  COMPLETED\n  STOPPED\n  CANCELLED\n}\n\nenum SequenceActivityType {\n  CREATED\n  UPDATED\n  ACTIVATED\n  PAUSED\n  ARCHIVED\n  DELETED\n  STEPS_CHANGED\n  ENROLLMENT_ADDED\n  ENROLLMENT_REMOVED\n  BULK_ENROLLED\n  PERFORMANCE_ALERT\n}\n\nenum EnrollmentActivityType {\n  ENROLLED\n  STEP_COMPLETED\n  PAUSED\n  RESUMED\n  STOPPED\n  COMPLETED\n  FAILED\n  RETRIED\n}\n\nmodel Sequence {\n  id          String         @id @default(cuid())\n  companyId   String\n  name        String\n  description String?        @db.Text\n  status      SequenceStatus @default(DRAFT)\n\n  // Analytics\n  useCount          Int       @default(0)\n  completionCount   Int       @default(0)\n  avgCompletionTime Float?\n  lastUsedAt        DateTime?\n\n  // Organization\n  tags        String[] @default([])\n  createdById String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  company     Company              @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  steps       SequenceStep[]\n  enrollments SequenceEnrollment[]\n  activities  SequenceActivity[]\n  createdBy   User?                @relation(\"SequenceCreator\", fields: [createdById], references: [id])\n\n  @@unique([companyId, name])\n  @@index([companyId, status])\n  @@index([companyId, tags])\n  @@index([useCount])\n}\n\nmodel SequenceStep {\n  id         String @id @default(cuid())\n  sequenceId String\n\n  sortOrder  Int    @default(0)\n  delayHours Int    @default(24)\n  action     String @default(\"send_message\")\n\n  // Action-specific fields\n  message    String? @db.Text\n  templateId String?\n  subject    String?\n  tagName    String?\n  webhookUrl String?\n  condition  String? @db.Text\n  metadata   Json    @default(\"{}\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sequence Sequence  @relation(fields: [sequenceId], references: [id], onDelete: Cascade)\n  template Template? @relation(fields: [templateId], references: [id])\n\n  @@index([sequenceId, sortOrder])\n}\n\nmodel SequenceEnrollment {\n  id         String @id @default(cuid())\n  sequenceId String\n  contactId  String\n  companyId  String\n\n  currentStep Int              @default(0)\n  status      EnrollmentStatus @default(ACTIVE)\n\n  // Timing\n  enrolledAt  DateTime  @default(now())\n  startedAt   DateTime?\n  lastStepAt  DateTime?\n  nextRunAt   DateTime?\n  completedAt DateTime?\n\n  // Control\n  pausedAt      DateTime?\n  pausedReason  String?\n  stoppedAt     DateTime?\n  stoppedReason String?\n\n  // Retry tracking\n  retryCount Int     @default(0)\n  lastError  String?\n\n  metadata Json @default(\"{}\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sequence   Sequence                     @relation(fields: [sequenceId], references: [id], onDelete: Cascade)\n  contact    Contact                      @relation(fields: [contactId], references: [id], onDelete: Cascade)\n  company    Company                      @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  activities SequenceEnrollmentActivity[]\n\n  @@unique([sequenceId, contactId])\n  @@index([companyId, status])\n  @@index([nextRunAt])\n  @@index([sequenceId, status])\n}\n\nmodel SequenceActivity {\n  id         String               @id @default(cuid())\n  sequenceId String\n  companyId  String\n  type       SequenceActivityType\n  actorType  String // user | ai | system\n  actorId    String?\n  title      String\n  body       String?\n  metadata   Json                 @default(\"{}\")\n  createdAt  DateTime             @default(now())\n\n  sequence Sequence @relation(fields: [sequenceId], references: [id], onDelete: Cascade)\n\n  @@index([sequenceId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel SequenceEnrollmentActivity {\n  id           String                 @id @default(cuid())\n  enrollmentId String\n  companyId    String\n  type         EnrollmentActivityType\n  actorType    String // user | ai | system | worker\n  actorId      String?\n  title        String\n  body         String?\n  metadata     Json                   @default(\"{}\")\n  createdAt    DateTime               @default(now())\n\n  enrollment SequenceEnrollment @relation(fields: [enrollmentId], references: [id], onDelete: Cascade)\n\n  @@index([enrollmentId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel CallLog {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String\n  agentId   String?\n  duration  Int? // seconds\n  outcome   String? // connected, no_answer, voicemail, callback\n  notes     String?\n  createdAt DateTime @default(now())\n\n  @@index([companyId, contactId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 3: SALES PIPELINE\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Pipeline {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  isDefault Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  stages PipelineStage[]\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\nmodel PipelineStage {\n  id          String @id @default(cuid())\n  pipelineId  String\n  name        String\n  color       String @default(\"#8b5cf6\")\n  sortOrder   Int\n  probability Int    @default(0) // 0-100\n\n  pipeline Pipeline @relation(fields: [pipelineId], references: [id], onDelete: Cascade)\n\n  @@index([pipelineId])\n}\n\nenum ProductActivityType {\n  CREATED\n  UPDATED\n  PRICE_CHANGED\n  COST_CHANGED\n  STOCK_ADJUSTED\n  STOCK_RESTOCKED\n  STOCK_LOW\n  STOCK_OUT\n  CATEGORY_CHANGED\n  TAG_ADDED\n  TAG_REMOVED\n  IMAGE_ADDED\n  IMAGE_REMOVED\n  VARIANT_ADDED\n  VARIANT_UPDATED\n  VARIANT_REMOVED\n  ACTIVATED\n  ARCHIVED\n  DELETED\n  CUSTOM\n}\n\nmodel Product {\n  id             String    @id @default(cuid())\n  companyId      String\n  name           String\n  description    String?\n  // Pricing — all amounts in smallest unit (paise/cents)\n  price          Int       @default(0)\n  costPrice      Int? // Used to compute margin\n  currency       String    @default(\"INR\")\n  // Identification\n  sku            String?\n  barcode        String?\n  // Categorization\n  category       String?\n  tags           String[]  @default([])\n  // Inventory\n  trackInventory Boolean   @default(false)\n  stock          Int       @default(0)\n  reorderLevel   Int       @default(0)\n  // Media\n  images         String[]  @default([]) // public URLs\n  // Variants — JSON array of {id, name, sku, price?, stock?, attributes: {color, size, ...}}\n  variants       Json      @default(\"[]\")\n  // State\n  isActive       Boolean   @default(true)\n  archivedAt     DateTime?\n  // Counters maintained by service\n  totalSold      Int       @default(0)\n  // Audit\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  dealLineItems DealLineItem[]\n  activities    ProductActivity[]\n\n  @@unique([companyId, sku])\n  @@index([companyId])\n  @@index([companyId, isActive])\n  @@index([companyId, category])\n  @@index([companyId, archivedAt])\n}\n\nmodel ProductActivity {\n  id        String              @id @default(cuid())\n  productId String\n  companyId String\n  type      ProductActivityType\n  actorType String // user | ai | system\n  actorId   String?\n  title     String\n  body      String?\n  metadata  Json                @default(\"{}\")\n  createdAt DateTime            @default(now())\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@index([productId, createdAt])\n  @@index([companyId, type])\n}\n\nmodel Quote {\n  id          String    @id @default(cuid())\n  companyId   String\n  contactId   String?\n  dealId      String?\n  quoteNumber String\n  status      String    @default(\"DRAFT\") // DRAFT, SENT, ACCEPTED, REJECTED, EXPIRED\n  subtotal    Int       @default(0)\n  tax         Int       @default(0)\n  discount    Int       @default(0)\n  total       Int       @default(0)\n  currency    String    @default(\"INR\")\n  validUntil  DateTime?\n  notes       String?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  lineItems QuoteLineItem[]\n\n  @@index([companyId])\n}\n\nmodel QuoteLineItem {\n  id        String  @id @default(cuid())\n  quoteId   String\n  productId String?\n  name      String\n  quantity  Int     @default(1)\n  unitPrice Int     @default(0)\n  total     Int     @default(0)\n\n  quote Quote @relation(fields: [quoteId], references: [id], onDelete: Cascade)\n\n  @@index([quoteId])\n}\n\nmodel Invoice {\n  id            String    @id @default(cuid())\n  companyId     String\n  contactId     String?\n  dealId        String?\n  invoiceNumber String\n  status        String    @default(\"UNPAID\") // UNPAID, PAID, OVERDUE, CANCELLED\n  subtotal      Int       @default(0)\n  tax           Int       @default(0)\n  total         Int       @default(0)\n  currency      String    @default(\"INR\")\n  dueDate       DateTime?\n  paidAt        DateTime?\n  notes         String?\n  createdAt     DateTime  @default(now())\n\n  lineItems InvoiceLineItem[]\n\n  @@index([companyId])\n  @@index([companyId, status])\n}\n\nmodel InvoiceLineItem {\n  id        String @id @default(cuid())\n  invoiceId String\n  name      String\n  quantity  Int    @default(1)\n  unitPrice Int    @default(0)\n  total     Int    @default(0)\n\n  invoice Invoice @relation(fields: [invoiceId], references: [id], onDelete: Cascade)\n\n  @@index([invoiceId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 4: MARKETING\n// ═══════════════════════════════════════════════════════════════════════════════\n\nenum CampaignStatus {\n  DRAFT\n  SCHEDULED\n  SENDING\n  PAUSED\n  COMPLETED\n  CANCELLED\n  FAILED\n}\n\nenum CampaignChannel {\n  WHATSAPP\n  EMAIL\n  SMS\n}\n\n/// How the campaign actually delivers messages.\n/// DIRECT    — campaign owns its own rate-limited sender\n/// BROADCAST — dispatches via an existing Broadcast on launch\n/// SEQUENCE  — enrolls the resolved audience into a Sequence\nenum CampaignSendMode {\n  DIRECT\n  BROADCAST\n  SEQUENCE\n}\n\nenum CampaignRecipientStatus {\n  PENDING\n  QUEUED\n  SENT\n  DELIVERED\n  READ\n  REPLIED\n  FAILED\n  SKIPPED\n  OPTED_OUT\n}\n\nenum CampaignActivityType {\n  CREATED\n  STATUS_CHANGED\n  SCHEDULED\n  LAUNCHED\n  PAUSED\n  RESUMED\n  CANCELLED\n  COMPLETED\n  AUDIENCE_UPDATED\n  RECIPIENTS_ADDED\n  RECIPIENTS_REMOVED\n  NOTE_ADDED\n  FIELD_UPDATED\n  BROADCAST_DISPATCHED\n  SEQUENCE_ENROLLED\n  RECIPIENT_SENT\n  RECIPIENT_FAILED\n  RECIPIENT_DELIVERED\n  RECIPIENT_READ\n  RECIPIENT_REPLIED\n  ERROR\n}\n\nmodel Campaign {\n  id          String           @id @default(cuid())\n  companyId   String\n  name        String\n  description String?\n  channel     CampaignChannel  @default(WHATSAPP)\n  sendMode    CampaignSendMode @default(DIRECT)\n  status      CampaignStatus   @default(DRAFT)\n\n  /// Template used to render per-recipient bodies (DIRECT mode only).\n  templateId  String?\n  /// Populated on launch when sendMode = BROADCAST.\n  broadcastId String?\n  /// Populated on launch when sendMode = SEQUENCE.\n  sequenceId  String?\n\n  startAt     DateTime?\n  startedAt   DateTime?\n  completedAt DateTime?\n  pausedAt    DateTime?\n  cancelledAt DateTime?\n\n  /// Audience filter — tags are AND-joined against contact.tags.\n  audienceTags           String[] @default([])\n  /// Explicit adds, merged with tag filter.\n  audienceContactIds     String[] @default([])\n  /// \"skip\" (default) or \"fail\" — what to do for opted-out contacts that match.\n  audienceOptOutBehavior String   @default(\"skip\")\n\n  /// Rate limit applied by the DIRECT-mode send processor (ms between sends).\n  throttleMs Int @default(2000)\n\n  /// Analytics snapshots — maintained by the worker.\n  totalRecipients Int @default(0)\n  sentCount       Int @default(0)\n  deliveredCount  Int @default(0)\n  readCount       Int @default(0)\n  repliedCount    Int @default(0)\n  failedCount     Int @default(0)\n  optedOutCount   Int @default(0)\n\n  /// Meta\n  tags            String[] @default([])\n  priority        String   @default(\"MEDIUM\") // LOW|MEDIUM|HIGH|URGENT\n  budget          Int?\n  notes           String?\n  errorMessage    String?\n  createdByUserId String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  recipients CampaignRecipient[]\n  activities CampaignActivity[]\n\n  @@index([companyId])\n  @@index([companyId, status])\n  @@index([companyId, startAt])\n  @@index([startAt, status])\n}\n\nmodel CampaignRecipient {\n  id           String                  @id @default(cuid())\n  campaignId   String\n  companyId    String\n  contactId    String\n  status       CampaignRecipientStatus @default(PENDING)\n  queuedAt     DateTime?\n  sentAt       DateTime?\n  deliveredAt  DateTime?\n  readAt       DateTime?\n  repliedAt    DateTime?\n  failedAt     DateTime?\n  errorReason  String?\n  /// Linked Message id once the outbound message is created.\n  messageId    String?\n  /// Rendered, personalized body for DIRECT sends. Stored so retries do not\n  /// re-render and the audit shows the exact text sent.\n  renderedText String?\n  metadata     Json                    @default(\"{}\")\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n\n  @@unique([campaignId, contactId])\n  @@index([campaignId, status])\n  @@index([companyId, status])\n  @@index([contactId])\n}\n\nmodel CampaignActivity {\n  id         String               @id @default(cuid())\n  campaignId String\n  companyId  String\n  type       CampaignActivityType\n  actorType  String // \"user\" | \"ai\" | \"system\" | \"worker\"\n  actorId    String?\n  title      String\n  body       String?\n  metadata   Json                 @default(\"{}\")\n  createdAt  DateTime             @default(now())\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n\n  @@index([campaignId, createdAt])\n  @@index([companyId, type, createdAt])\n}\n\nmodel Form {\n  id          String   @id @default(cuid())\n  companyId   String\n  name        String\n  fields      Json     @default(\"[]\") // [{name, type, required, label}]\n  isActive    Boolean  @default(true)\n  submitCount Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  submissions FormSubmission[]\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\nmodel FormSubmission {\n  id          String   @id @default(cuid())\n  formId      String\n  companyId   String\n  data        Json     @default(\"{}\")\n  contactId   String?\n  leadId      String?\n  utmSource   String?\n  utmMedium   String?\n  utmCampaign String?\n  ipAddress   String?\n  createdAt   DateTime @default(now())\n\n  form Form @relation(fields: [formId], references: [id], onDelete: Cascade)\n\n  @@index([formId])\n  @@index([companyId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 5: AUTOMATION\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Workflow {\n  id        String    @id @default(cuid())\n  companyId String\n  name      String\n  isActive  Boolean   @default(false)\n  trigger   Json      @default(\"{}\") // {type: \"contact_created\", conditions: {...}}\n  steps     Json      @default(\"[]\") // [{type: \"action\", action: \"send_message\", config: {...}}]\n  runCount  Int       @default(0)\n  lastRunAt DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  executions WorkflowExecution[]\n\n  @@unique([companyId, name])\n  @@index([companyId, isActive])\n}\n\nmodel WorkflowExecution {\n  id          String    @id @default(cuid())\n  workflowId  String\n  companyId   String\n  contactId   String?\n  status      String    @default(\"RUNNING\") // RUNNING, COMPLETED, FAILED\n  steps       Json      @default(\"[]\") // [{step, status, result, timestamp}]\n  error       String?\n  startedAt   DateTime  @default(now())\n  completedAt DateTime?\n\n  workflow Workflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n\n  @@index([workflowId])\n  @@index([companyId, status])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 7: CUSTOMER SUPPORT\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Ticket {\n  id              String    @id @default(cuid())\n  companyId       String\n  contactId       String?\n  assignedToId    String?\n  title           String\n  description     String?\n  status          String    @default(\"OPEN\") // OPEN, IN_PROGRESS, WAITING, RESOLVED, CLOSED\n  priority        String    @default(\"MEDIUM\") // LOW, MEDIUM, HIGH, CRITICAL\n  category        String? // bug, feature, billing, general\n  source          String    @default(\"whatsapp\") // whatsapp, email, web, manual\n  firstResponseAt DateTime?\n  resolvedAt      DateTime?\n  closedAt        DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n\n  comments TicketComment[]\n\n  @@index([companyId, status])\n  @@index([companyId, assignedToId])\n  @@index([companyId, priority])\n}\n\nmodel TicketComment {\n  id         String   @id @default(cuid())\n  ticketId   String\n  authorId   String?\n  content    String\n  isInternal Boolean  @default(false) // internal notes not visible to customer\n  createdAt  DateTime @default(now())\n\n  ticket Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n\n  @@index([ticketId])\n}\n\nmodel KnowledgeBaseArticle {\n  id        String   @id @default(cuid())\n  companyId String\n  title     String\n  content   String\n  category  String?\n  isPublic  Boolean  @default(true)\n  viewCount Int      @default(0)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n  @@index([companyId, category])\n}\n\nmodel SlaPolicy {\n  id                String  @id @default(cuid())\n  companyId         String\n  name              String\n  firstResponseMins Int     @default(60)\n  resolutionMins    Int     @default(480)\n  priority          String  @default(\"MEDIUM\")\n  isActive          Boolean @default(true)\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 8: REPORTING\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel CustomReport {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  entity    String // contacts, leads, deals, tickets, payments\n  filters   Json     @default(\"{}\")\n  groupBy   String?\n  columns   String[]\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n}\n\nmodel ScheduledReport {\n  id         String    @id @default(cuid())\n  companyId  String\n  reportId   String\n  frequency  String    @default(\"weekly\") // daily, weekly, monthly\n  recipients String[] // email addresses\n  lastSentAt DateTime?\n  nextRunAt  DateTime?\n  isActive   Boolean   @default(true)\n  createdAt  DateTime  @default(now())\n\n  @@index([companyId])\n  @@index([nextRunAt, isActive])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 9: INTEGRATIONS\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Integration {\n  id        String   @id @default(cuid())\n  companyId String\n  type      String // google_calendar, outlook, slack, discord, telegram, instagram\n  config    Json     @default(\"{}\") // encrypted config\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([companyId, type])\n  @@index([companyId])\n}\n\nmodel CalendarEvent {\n  id          String   @id @default(cuid())\n  companyId   String\n  contactId   String?\n  dealId      String?\n  title       String\n  description String?\n  startAt     DateTime\n  endAt       DateTime\n  location    String?\n  externalId  String?\n  createdAt   DateTime @default(now())\n\n  @@index([companyId])\n  @@index([companyId, startAt])\n}\n\nmodel ActivityLog {\n  id         String   @id @default(cuid())\n  companyId  String\n  userId     String?\n  contactId  String?\n  entityType String // contact, lead, deal, ticket, task\n  entityId   String\n  action     String // created, updated, status_changed, assigned, etc.\n  details    Json     @default(\"{}\")\n  createdAt  DateTime @default(now())\n\n  @@index([companyId, createdAt])\n  @@index([companyId, entityType, entityId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 10: DOCUMENTS & SECURITY\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Document {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String?\n  dealId    String?\n  name      String\n  type      String // proposal, contract, invoice_pdf, other\n  fileUrl   String\n  fileSize  Int?\n  mimeType  String?\n  createdAt DateTime @default(now())\n\n  signatures DocumentSignature[]\n\n  @@index([companyId])\n  @@index([companyId, contactId])\n}\n\nmodel DocumentSignature {\n  id          String    @id @default(cuid())\n  documentId  String\n  signerName  String\n  signerEmail String?\n  status      String    @default(\"PENDING\") // PENDING, SIGNED, DECLINED\n  signedAt    DateTime?\n  createdAt   DateTime  @default(now())\n\n  document Document @relation(fields: [documentId], references: [id], onDelete: Cascade)\n\n  @@index([documentId])\n}\n\nmodel ApiKey {\n  id         String    @id @default(cuid())\n  companyId  String\n  name       String\n  keyHash    String    @unique // hashed API key\n  prefix     String // first 8 chars for display\n  scopes     String[] // [\"contacts:read\", \"contacts:write\", etc.]\n  lastUsedAt DateTime?\n  expiresAt  DateTime?\n  isActive   Boolean   @default(true)\n  createdAt  DateTime  @default(now())\n\n  @@index([companyId])\n  @@index([keyHash])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// AI CHAT CONVERSATIONS (persistent)\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel ChatConversation {\n  id        String   @id @default(cuid())\n  companyId String\n  userId    String\n  title     String   @default(\"New Chat\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  messages ChatMessage[]\n\n  @@index([companyId, userId, updatedAt])\n}\n\nmodel ChatMessage {\n  id             String   @id @default(cuid())\n  conversationId String\n  role           String // user, assistant\n  content        String\n  toolCalls      Json? // [{tool, args, result}]\n  attachments    Json? // [{kind, mimeType, fileName, size, dataBase64?, text?}]\n  provider       String?\n  model          String?\n  latencyMs      Int?\n  createdAt      DateTime @default(now())\n\n  conversation ChatConversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n\n  @@index([conversationId, createdAt])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// AI MEMORY (knowledge base for AI context — legacy key/value store, deprecated\n// in favor of MemoryFile/MemoryChunk/RecallEntry. Kept for backward compatibility.)\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel AiMemory {\n  id        String   @id @default(cuid())\n  companyId String\n  title     String\n  content   String // The knowledge/fact/instruction\n  category  String   @default(\"general\") // general, product, policy, faq, instruction\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId, isActive])\n  @@index([companyId, category])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// OPENCLAW-STYLE MEMORY SYSTEM\n//   - MemoryFile: a markdown file (e.g. MEMORY.md, memory/2026-04-09-foo.md)\n//   - MemoryChunk: a chunk of a file with embedding + tsvector for hybrid search\n//   - RecallEntry: tracks how often a chunk was recalled, used by the dreaming\n//     job to promote short-term recalls into long-term MEMORY.md\n// The vector(1536) and tsvector columns are added by manual_pgvector.sql.\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel MemoryFile {\n  id        String   @id @default(cuid())\n  companyId String\n  path      String // e.g. \"MEMORY.md\", \"memory/2026-04-09-api-fix.md\"\n  source    String   @default(\"memory\") // memory | wiki | session\n  hash      String // SHA-256 of content for change detection\n  content   String // Full markdown content\n  size      Int\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  chunks MemoryChunk[]\n\n  @@unique([companyId, path])\n  @@index([companyId])\n  @@index([companyId, source])\n}\n\nmodel MemoryChunk {\n  id         String                       @id @default(cuid())\n  companyId  String\n  fileId     String\n  path       String // duplicated for fast filtering\n  source     String // memory | wiki | session\n  startLine  Int\n  endLine    Int\n  hash       String\n  text       String\n  model      String // embedding model used (or \"none\" for keyword-only)\n  // Vector & FTS columns are managed by manual_pgvector.sql:\n  //   embedding   vector(1536)\n  //   textSearch  tsvector (GENERATED from text)\n  embedding  Unsupported(\"vector(1536)\")?\n  textSearch Unsupported(\"tsvector\")?\n  createdAt  DateTime                     @default(now())\n  updatedAt  DateTime                     @updatedAt\n\n  file MemoryFile @relation(fields: [fileId], references: [id], onDelete: Cascade)\n\n  @@index([companyId])\n  @@index([companyId, source])\n  @@index([fileId])\n}\n\nmodel RecallEntry {\n  id              String    @id @default(cuid())\n  companyId       String\n  key             String // \"{source}:{path}:{startLine}:{endLine}\"\n  path            String\n  startLine       Int\n  endLine         Int\n  source          String\n  snippet         String\n  recallCount     Int       @default(1)\n  totalScore      Float     @default(0)\n  maxScore        Float     @default(0)\n  firstRecalledAt DateTime  @default(now())\n  lastRecalledAt  DateTime  @default(now())\n  queryHashes     String[] // up to 32\n  recallDays      String[] // ISO dates, up to 16\n  conceptTags     String[] // up to 8\n  promotedAt      DateTime?\n\n  @@unique([companyId, key])\n  @@index([companyId])\n  @@index([companyId, promotedAt])\n}\n"
}

